.darma-loader-darma-custom-348 {color: var(--loader-color, #f97316);
  display: inline-grid;
  width: 40px;
  aspect-ratio: 1;
}.darma-loader-darma-custom-348:before,.darma-loader-darma-custom-348:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-conic-gradient(var(--loader-color, #f97316) 0 60deg,var(--loader-secondary-color, #facc15) 0 120deg);
}.darma-loader-darma-custom-348:before {transform: rotate(0turn) translate(100%) rotate(0turn);
  animation: darma-loader-darma-custom-348-l5 4s linear infinite;
}.darma-loader-darma-custom-348:after {padding: 20%;
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
  scale: -1 1;
}@keyframes darma-loader-darma-custom-348-l5 {to{transform: rotate(1turn) translate(100%) rotate(1turn)}}

